'use client';

import React from 'react';
import { useOS } from '../../context/OSContext';
import { 
  User, 
  Cpu, 
  BarChart3, 
  FolderOpen, 
  Settings,
  Shield,
  HelpCircle
} from 'lucide-react';

interface DockProps {
  onShortcutContextMenu?: (x: number, y: number, id: string) => void;
}

export const Dock: React.FC<DockProps> = ({ onShortcutContextMenu }) => {
  const { windows, openWindow, activeWindowId, focusWindow, minimizeWindow } = useOS();

  const dockItems = [
    { id: 'portfolio', title: 'Portfolio', icon: User, color: 'from-blue-500 to-indigo-500' },
    { id: 'ai_dashboard', title: 'AI Command Center', icon: Cpu, color: 'from-purple-500 to-pink-500' },
    { id: 'marketing_desk', title: 'Marketing KPI', icon: BarChart3, color: 'from-emerald-500 to-teal-500' },
    { id: 'workspace', title: 'Workspace', icon: FolderOpen, color: 'from-orange-500 to-red-500' },
    { id: 'admin', title: 'CMS Admin', icon: Settings, color: 'from-amber-500 to-yellow-600' }
  ];

  const handleIconClick = (id: string) => {
    const win = windows.find(w => w.id === id);
    if (win) {
      const mode = win.launchMode || 'desktop';
      if (mode === 'new_tab' || mode === 'popup') {
        openWindow(id, mode);
        return;
      }
      if (win.isOpen && !win.isMinimized) {
        // If it's already active, minimize it, otherwise focus it
        if (activeWindowId === id) {
          minimizeWindow(id);
        } else {
          focusWindow(id);
        }
      } else {
        openWindow(id);
      }
    }
  };

  return (
    <div className="fixed bottom-3 left-1/2 -translate-x-1/2 z-40 select-none">
      <div className="glass-panel flex items-end gap-3 px-4 py-2.5 rounded-2xl border border-white/10 shadow-2xl relative">
        {dockItems.map((item) => {
          const winState = windows.find(w => w.id === item.id);
          const isOpen = winState?.isOpen;
          const isMinimized = winState?.isMinimized;
          const isActive = activeWindowId === item.id && !isMinimized;
          const Icon = item.icon;

          return (
            <div 
              key={item.id} 
              className="flex flex-col items-center group relative cursor-pointer"
              onClick={() => handleIconClick(item.id)}
              onContextMenu={(e) => {
                if (onShortcutContextMenu) {
                  e.preventDefault();
                  onShortcutContextMenu(e.clientX, e.clientY, item.id);
                }
              }}
            >
              {/* Tooltip */}
              <span className="absolute -top-10 scale-0 group-hover:scale-100 transition-all duration-150 origin-bottom bg-slate-900/90 text-white border border-white/10 text-[10px] px-2 py-1 rounded shadow-lg whitespace-nowrap z-50">
                {item.title}
              </span>

              {/* Icon Wrapper */}
              <div 
                className={`w-12 h-12 rounded-xl flex items-center justify-center bg-gradient-to-tr ${item.color} shadow-lg transition-all duration-300 transform group-hover:-translate-y-2 group-hover:scale-110 active:scale-95 ${
                  isActive ? 'ring-2 ring-white shadow-cyan-500/20' : 'opacity-85 hover:opacity-100'
                }`}
              >
                <Icon className="w-6 h-6 text-white" />
              </div>

              {/* Active / Running Indicator Dot */}
              <div className="h-1.5 flex items-center justify-center mt-1">
                {isOpen && (
                  <span className={`w-1 h-1 rounded-full transition-all duration-300 ${
                    isActive ? 'bg-cyan-400 w-3 h-1 shadow-[0_0_5px_#22d3ee]' : 'bg-white/50'
                  }`} />
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};
