'use client';

import React, { useState, useEffect } from 'react';
import { useOS, OSTheme } from '../../context/OSContext';
import { 
  Play, 
  Pause, 
  Volume2, 
  VolumeX, 
  Wifi, 
  Battery, 
  ChevronDown, 
  Sun, 
  Moon, 
  Settings, 
  Compass, 
  FolderSync, 
  Sparkles,
  Terminal,
  LogOut
} from 'lucide-react';

export const TopBar: React.FC = () => {
  const { 
    theme, setTheme, 
    font, 
    activeWindowId, 
    windows, 
    openWindow, 
    resetWindowPositions,
    musicPlaying, setMusicPlaying,
    musicVolume, setMusicVolume
  } = useOS();
  
  const [time, setTime] = useState<string>('');
  const [dateStr, setDateStr] = useState<string>('');
  const [systemDropdown, setSystemDropdown] = useState<boolean>(false);
  const [controlDropdown, setControlDropdown] = useState<boolean>(false);

  // Time & Date effect
  useEffect(() => {
    const updateDateTime = () => {
      const d = new Date();
      setTime(d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
      setDateStr(d.toLocaleDateString([], { weekday: 'short', month: 'short', day: 'numeric' }));
    };
    updateDateTime();
    const interval = setInterval(updateDateTime, 60000);
    return () => clearInterval(interval);
  }, []);

  const activeWindow = windows.find(w => w.id === activeWindowId);

  // System menu items
  const systemThemes: { name: string; id: OSTheme }[] = [
    { name: 'Liquid Glass (Spatial)', id: 'glass' },
    { name: 'Apple Cupertino', id: 'apple' },
    { name: 'Gotham Batman', id: 'batman' },
    { name: 'Cyberpunk 2077', id: 'cyberpunk' },
    { name: 'Hyper Neon', id: 'neon' },
    { name: 'Matrix Digital', id: 'matrix' },
    { name: 'Midnight Dark', id: 'dark' },
    { name: 'Clean Light', id: 'light' },
    { name: 'Royal Luxury', id: 'luxury' }
  ];

  return (
    <div className="w-full h-8 glass-panel px-4 flex items-center justify-between text-xs select-none border-b z-40 relative">
      {/* Left Menu Section */}
      <div className="flex items-center gap-4">
        {/* Apple/Batman Logo Icon based on theme */}
        <div 
          className="font-bold flex items-center gap-1 cursor-pointer py-1 px-2 rounded hover:bg-white/10 transition-colors"
          onClick={() => setSystemDropdown(!systemDropdown)}
        >
          {theme === 'batman' ? (
            <span className="text-yellow-500 font-extrabold text-sm tracking-tighter">🦇</span>
          ) : theme === 'matrix' ? (
            <span className="text-green-500 font-extrabold text-sm font-mono">[M]</span>
          ) : theme === 'apple' ? (
            <span className="text-black dark:text-white font-extrabold text-sm"></span>
          ) : (
            <Sparkles className="w-4 h-4 text-cyan-400 glowing-text" />
          )}
          <span className="font-semibold tracking-wider text-[11px] ml-1">MK DIGIXX OS</span>
          <ChevronDown className="w-3 h-3 opacity-60 ml-0.5" />
        </div>

        {/* Active Application Name */}
        {activeWindow && (
          <div className="hidden sm:flex items-center gap-2 border-l border-white/15 pl-4">
            <span className="font-medium text-white/90 glowing-text capitalize">{activeWindow.title}</span>
            <span className="opacity-40">File</span>
            <span className="opacity-40">Edit</span>
            <span className="opacity-40">View</span>
          </div>
        )}
      </div>

      {/* Center: System Status Indicator */}
      <div className="hidden md:flex items-center gap-2 px-3 py-0.5 rounded-full bg-white/5 border border-white/5">
        <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
        <span className="text-[10px] text-white/60 tracking-wider">System OK | Core Temp 42°C | Lighthouse 99+</span>
      </div>

      {/* Right Controls Section */}
      <div className="flex items-center gap-4">
        {/* Music Player */}
        <div className="flex items-center gap-2 border-r border-white/15 pr-3 py-1">
          <button 
            onClick={() => setMusicPlaying(!musicPlaying)}
            className="p-1 rounded hover:bg-white/10 transition-colors text-white/80 hover:text-white"
            title="Ambient Music Toggle"
          >
            {musicPlaying ? (
              <span className="flex gap-0.5 items-end h-3 w-4">
                <span className="w-[2px] bg-cyan-400 animate-[pulse_0.8s_infinite] h-full"></span>
                <span className="w-[2px] bg-cyan-400 animate-[pulse_1.2s_infinite] h-1/2"></span>
                <span className="w-[2px] bg-cyan-400 animate-[pulse_0.9s_infinite] h-4/5"></span>
                <span className="w-[2px] bg-cyan-400 animate-[pulse_1.1s_infinite] h-2/3"></span>
              </span>
            ) : (
              <VolumeX className="w-3.5 h-3.5 text-white/50" />
            )}
          </button>
          {musicPlaying && (
            <input 
              type="range" 
              min="0" 
              max="1" 
              step="0.05" 
              value={musicVolume} 
              onChange={(e) => setMusicVolume(parseFloat(e.target.value))}
              className="w-12 h-1 bg-white/20 rounded-lg appearance-none cursor-pointer accent-cyan-400"
            />
          )}
        </div>

        {/* System Indicators */}
        <div className="flex items-center gap-2.5 text-white/70">
          <Wifi className="w-3.5 h-3.5 text-green-400" />
          <div className="flex items-center gap-0.5">
            <span className="text-[10px]">100%</span>
            <Battery className="w-4 h-4 text-green-400" />
          </div>
        </div>

        {/* Quick Settings Icon */}
        <button 
          onClick={() => setControlDropdown(!controlDropdown)}
          className="p-1.5 rounded hover:bg-white/10 transition-colors text-white/70 hover:text-white"
        >
          <Settings className="w-3.5 h-3.5" />
        </button>

        {/* Clock & Date */}
        <div className="font-semibold text-white/90 text-[11px] select-none hover:bg-white/10 px-2 py-0.5 rounded cursor-pointer">
          {dateStr} {time}
        </div>
      </div>

      {/* System Dropdown (Start Menu) */}
      {systemDropdown && (
        <>
          <div className="fixed inset-0 z-40" onClick={() => setSystemDropdown(false)}></div>
          <div className="absolute left-4 top-9 w-60 glass-panel-heavy p-2 rounded-lg shadow-2xl border border-white/15 z-50 text-white flex flex-col gap-1">
            <div className="px-3 py-1.5 border-b border-white/10 flex items-center gap-2 mb-1">
              <Terminal className="w-3.5 h-3.5 text-cyan-400" />
              <div>
                <p className="font-bold text-[11px]">Manoj&apos;s Command Center</p>
                <p className="text-[9px] text-white/50">Build v2.0.1 (Linux-aarch64)</p>
              </div>
            </div>

            <button 
              onClick={() => { openWindow('portfolio'); setSystemDropdown(false); }}
              className="w-full text-left px-3 py-1.5 rounded hover:bg-white/15 transition-colors flex items-center gap-2"
            >
              <span>👤</span> Renders Portfolio
            </button>
            <button 
              onClick={() => { openWindow('ai_dashboard'); setSystemDropdown(false); }}
              className="w-full text-left px-3 py-1.5 rounded hover:bg-white/15 transition-colors flex items-center gap-2"
            >
              <span>🤖</span> AI Marketing Agents
            </button>
            <button 
              onClick={() => { openWindow('marketing_desk'); setSystemDropdown(false); }}
              className="w-full text-left px-3 py-1.5 rounded hover:bg-white/15 transition-colors flex items-center gap-2"
            >
              <span>📈</span> Performance Metrics
            </button>
            <button 
              onClick={() => { openWindow('workspace'); setSystemDropdown(false); }}
              className="w-full text-left px-3 py-1.5 rounded hover:bg-white/15 transition-colors flex items-center gap-2"
            >
              <span>📁</span> Workspace Productivity
            </button>

            <hr className="border-white/10 my-1" />

            <button 
              onClick={() => { resetWindowPositions(); setSystemDropdown(false); }}
              className="w-full text-left px-3 py-1.5 rounded hover:bg-white/15 transition-colors flex items-center gap-2 text-yellow-400/90"
            >
              <FolderSync className="w-3.5 h-3.5" /> Reset Window Layouts
            </button>
            <button 
              onClick={() => { openWindow('admin'); setSystemDropdown(false); }}
              className="w-full text-left px-3 py-1.5 rounded hover:bg-white/15 transition-colors flex items-center gap-2 text-cyan-400"
            >
              <Settings className="w-3.5 h-3.5" /> CMS / OS Admin panel
            </button>
          </div>
        </>
      )}

      {/* Control Dropdown (Quick Settings) */}
      {controlDropdown && (
        <>
          <div className="fixed inset-0 z-40" onClick={() => setControlDropdown(false)}></div>
          <div className="absolute right-12 top-9 w-64 glass-panel-heavy p-3 rounded-lg shadow-2xl border border-white/15 z-50 text-white flex flex-col gap-2">
            <p className="font-bold text-[11px] border-b border-white/10 pb-1 flex items-center gap-1.5">
              <Compass className="w-3.5 h-3.5 text-cyan-400" />
              Quick Customizer
            </p>
            
            {/* System Themes selector */}
            <div className="flex flex-col gap-1 mt-1">
              <label className="text-[10px] text-white/50 font-medium">OS Layout Style</label>
              <div className="grid grid-cols-2 gap-1 max-h-36 overflow-y-auto pr-1">
                {systemThemes.map(t => (
                  <button
                    key={t.id}
                    onClick={() => setTheme(t.id)}
                    className={`text-left text-[10px] px-2 py-1 rounded transition-colors ${
                      theme === t.id ? 'bg-cyan-500/35 text-white font-semibold' : 'bg-white/5 hover:bg-white/15 text-white/70'
                    }`}
                  >
                    {t.name}
                  </button>
                ))}
              </div>
            </div>

            <hr className="border-white/10 my-1" />

            <div className="flex justify-between items-center text-[10px]">
              <span className="text-white/60">Selected Theme:</span>
              <span className="font-semibold text-cyan-400 uppercase tracking-wider">{theme}</span>
            </div>
            
            <div className="flex justify-between items-center text-[10px]">
              <span className="text-white/60">Selected Font:</span>
              <span className="font-semibold text-cyan-400">{font}</span>
            </div>

            <button 
              onClick={() => { openWindow('admin'); setControlDropdown(false); }}
              className="w-full mt-1 glass-button py-1 text-center font-bold hover:bg-cyan-500/20"
            >
              Open Theme Settings
            </button>
          </div>
        </>
      )}
    </div>
  );
};
